create table dirkspzm32.pzm_produktionsbereiche (
    pb_id                number(*, 0) not null enable,
    pb_name              varchar2(100 char) not null enable,
    pb_bemerkungen       varchar2(255 char),
    pb_personal_abt_id   number(*, 0),
    pb_kst_id            number(*, 0),
    pb_adress_id         number(*, 0),
    pb_extern            varchar2(1 char) default 'F' not null enable,
    pb_schnittstelle     varchar2(50 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_produktionsbereiche
    add constraint pk_pb_id primary key ( pb_id )
        using index enable;


